Let's create a new bot, which will ask the user for his data, and then send some statistics from the collected information. Take echo-bot, from the Introduction , and gradually improve it step by step. Starting point Right now we have the following code: from botx import Bot , ExpressServer , IncomingMessage , Message , Status from fastapi import FastAPI from starlette.status import HTTP_202_ACCEPTED bot = Bot ( known_hosts = [ ExpressServer ( host = "cts.example.com" , secret_key = "secret" )]) @bot . default ( include_in_status = False ) async def echo_handler ( message : Message ) -> None : await bot . answer_message ( message . body , message ) app = FastAPI () app . add_event_handler ( "shutdown" , bot . shutdown ) @app . get ( "/status" , response_model = Status ) async def bot_status () -> Status : return await bot . status () @app . post ( "/command" , status_code = HTTP_202_ACCEPTED ) async def bot_command ( message : IncomingMessage ) -> None : await bot . execute_command ( message . dict ()) First, let's see how this code works We will explain only those parts that relate to pybotx , and not to the frameworks used in this documentation. Step 1: import Bot , Message , Status and other classes from botx import Bot , ExpressServer , IncomingMessage , Message , Status from fastapi import FastAPI from starlette.status import HTTP_202_ACCEPTED bot = Bot ( known_hosts = [ ExpressServer ( host = "cts.example.com" , secret_key = "secret" )]) @bot . default ( include_in_status = False ) async def echo_handler ( message : Message ) -> None : await bot . answer_message ( message . body , message ) app = FastAPI () app . add_event_handler ( "shutdown" , bot . shutdown ) @app . get ( "/status" , response_model = Status ) async def bot_status () -> Status : return await bot . status () @app . post ( "/command" , status_code = HTTP_202_ACCEPTED ) async def bot_command ( message : IncomingMessage ) -> None : await bot . execute_command ( message . dict ()) Bot is a class that provides all the core functionality to your bots. Message provides data to your handlers for commands. Status is used here only to document the FastAPI route, but in fact it stores information about public commands that user of your bot should see in menu. ExpressServer is used for storing information about servers with which your bot is able to communicate. IncomingMessage is a pydantic model that is used for base validating of data, that was received on your bot's webhook. Step 2: initialize your Bot from botx import Bot , ExpressServer , IncomingMessage , Message , Status from fastapi import FastAPI from starlette.status import HTTP_202_ACCEPTED bot = Bot ( known_hosts = [ ExpressServer ( host = "cts.example.com" , secret_key = "secret" )]) @bot . default ( include_in_status = False ) async def echo_handler ( message : Message ) -> None : await bot . answer_message ( message . body , message ) app = FastAPI () app . add_event_handler ( "shutdown" , bot . shutdown ) @app . get ( "/status" , response_model = Status ) async def bot_status () -> Status : return await bot . status () @app . post ( "/command" , status_code = HTTP_202_ACCEPTED ) async def bot_command ( message : IncomingMessage ) -> None : await bot . execute_command ( message . dict ()) The bot variable will be an "instance" of the class Bot . We also register an instance of the cts server to get tokens and the ability to send requests to the API. Step 3: define default handler from botx import Bot , ExpressServer , IncomingMessage , Message , Status from fastapi import FastAPI from starlette.status import HTTP_202_ACCEPTED bot = Bot ( known_hosts = [ ExpressServer ( host = "cts.example.com" , secret_key = "secret" )]) @bot . default ( include_in_status = False ) async def echo_handler ( message : Message ) -> None : await bot . answer_message ( message . body , message ) app = FastAPI () app . add_event_handler ( "shutdown" , bot . shutdown ) @app . get ( "/status" , response_model = Status ) async def bot_status () -> Status : return await bot . status () @app . post ( "/command" , status_code = HTTP_202_ACCEPTED ) async def bot_command ( message : IncomingMessage ) -> None : await bot . execute_command ( message . dict ()) This handler will be called for all commands that have not appropriate handlers. We also set include_in_status=False so that handler won't be visible in menu and it won't complain about "wrong" body generated for it automatically. Step 4: send text to user from botx import Bot , ExpressServer , IncomingMessage , Message , Status from fastapi import FastAPI from starlette.status import HTTP_202_ACCEPTED bot = Bot ( known_hosts = [ ExpressServer ( host = "cts.example.com" , secret_key = "secret" )]) @bot . default ( include_in_status = False ) async def echo_handler ( message : Message ) -> None : await bot . answer_message ( message . body , message ) app = FastAPI () app . add_event_handler ( "shutdown" , bot . shutdown ) @app . get ( "/status" , response_model = Status ) async def bot_status () -> Status : return await bot . status () @app . post ( "/command" , status_code = HTTP_202_ACCEPTED ) async def bot_command ( message : IncomingMessage ) -> None : await bot . execute_command ( message . dict ()) .answer_message will send text to the user by using sync_id , bot_id and host data from the Message instance. This is a simple wrapper for the .send method, which is used to gain more control over sending messages process, allowing you to specify a different host, bot_id, sync_id, group_chat_id or a list of them. Step 5: register handler for bot proper shutdown. from botx import Bot , ExpressServer , IncomingMessage , Message , Status from fastapi import FastAPI from starlette.status import HTTP_202_ACCEPTED bot = Bot ( known_hosts = [ ExpressServer ( host = "cts.example.com" , secret_key = "secret" )]) @bot . default ( include_in_status = False ) async def echo_handler ( message : Message ) -> None : await bot . answer_message ( message . body , message ) app = FastAPI () app . add_event_handler ( "shutdown" , bot . shutdown ) @app . get ( "/status" , response_model = Status ) async def bot_status () -> Status : return await bot . status () @app . post ( "/command" , status_code = HTTP_202_ACCEPTED ) async def bot_command ( message : IncomingMessage ) -> None : await bot . execute_command ( message . dict ()) The .shutdown method is used to stop pending handler. You must call them to be sure that the bot will work properly. Step 6: define webhooks for bot from botx import Bot , ExpressServer , IncomingMessage , Message , Status from fastapi import FastAPI from starlette.status import HTTP_202_ACCEPTED bot = Bot ( known_hosts = [ ExpressServer ( host = "cts.example.com" , secret_key = "secret" )]) @bot . default ( include_in_status = False ) async def echo_handler ( message : Message ) -> None : await bot . answer_message ( message . body , message ) app = FastAPI () app . add_event_handler ( "shutdown" , bot . shutdown ) @app . get ( "/status" , response_model = Status ) async def bot_status () -> Status : return await bot . status () @app . post ( "/command" , status_code = HTTP_202_ACCEPTED ) async def bot_command ( message : IncomingMessage ) -> None : await bot . execute_command ( message . dict ()) Here we define 2 FastAPI routes: GET on /status will tell BotX API which commands are available for your bot. POST on /command will receive data for incoming messages for your bot and execute handlers for commands. Info If .execute_command did not find a handler for the command in the message, it will raise an NoMatch error in background, which you probably want to handle . You can register default handler to process all commands that do not have their own handler. Step 7 (Improvement): Reply to user if message was received from host, which is not registered We can send to BotX API a special response, that will say to user that bot can not communicate with user properly, since message was received from unknown host. We do it by handling ServerUnknownError and returning to BotX API information about error. from botx import ( Bot , BotDisabledErrorData , BotDisabledResponse , ExpressServer , IncomingMessage , Message , ServerUnknownError , Status , ) from fastapi import FastAPI from starlette.requests import Request from starlette.responses import JSONResponse , Response from starlette.status import HTTP_202_ACCEPTED , HTTP_503_SERVICE_UNAVAILABLE bot = Bot ( known_hosts = [ ExpressServer ( host = "cts.example.com" , secret_key = "secret" )]) @bot . default ( include_in_status = False ) async def echo_handler ( message : Message ) -> None : await bot . answer_message ( message . body , message ) app = FastAPI () app . add_event_handler ( "shutdown" , bot . shutdown ) @app . get ( "/status" , response_model = Status ) async def bot_status () -> Status : return await bot . status () @app . post ( "/command" , status_code = HTTP_202_ACCEPTED ) async def bot_command ( message : IncomingMessage ) -> None : await bot . execute_command ( message . dict ()) @app . exception_handler ( ServerUnknownError ) async def message_from_unknown_server_hanlder ( _request : Request , exc : ServerUnknownError ) -> Response : return JSONResponse ( status_code = HTTP_503_SERVICE_UNAVAILABLE , content = BotDisabledResponse ( error_data = BotDisabledErrorData ( status_message = ( f "Sorry, bot can not communicate with user from {exc.host} CTS" ) ) ) . dict (), ) Define new handlers Let's define a new handler that will trigger a chain of questions for the user to collect information. We'll use the /fill-info command to start the chain: from botx import Bot , ExpressServer , IncomingMessage , Message , Status from fastapi import FastAPI from starlette.status import HTTP_202_ACCEPTED users_data = {} bot = Bot ( known_hosts = [ ExpressServer ( host = "cts.example.com" , secret_key = "secret" )]) @bot . default ( include_in_status = False ) async def echo_handler ( message : Message ) -> None : await bot . answer_message ( message . body , message ) @bot . handler async def fill_info ( message : Message ) -> None : if message . user_huid not in users_data : text = ( "Hi! I'm a bot that will ask some questions about you. 
 " "First of all: what is your name?" ) else : text = ( "You've already filled out information about yourself. 
